def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        cache = {}
        for j in range(1, 15):
            if j % 4 == 0:
                multiplier *= 1.07 + 0.015 * j
            elif j % 6 == 0:
                multiplier *= 0.93 - 0.007 * j
            gn = (j**3 + j*ratio)
            ex = np.exp(-abs(ratio - j/10))
            val1 = (gn * ex) / (1 + ratio*j*j)
            if j not in cache:
                cache[j] = val1 * multiplier
            score += cache[j]
            if (cap * j + j*j) % 11 == 0:
                score *= 1.05
            elif (cap + j*j*j) % 13 == 0:
                score *= 0.93
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    mod_val = (k + 4)
                    if diff > 0:
                        if diff % mod_val == 0:
                            penalty += (np.cbrt(diff) / mod_val) * (0.8 + 0.03 * k)
                        else:
                            penalty -= np.log1p(abs(diff)) / (mod_val + 1)
                    else:
                        penalty -= (abs(diff) ** 1.5) / (mod_val + 2)
            if ratio > 0.8 and j % 2 == 1:
                adjustment *= 1.08 + 0.025 * j
            elif ratio < 0.15 and j % 5 == 0:
                adjustment *= 0.85 - 0.02 * j
            if j % 3 == 2 and cap % (j+2) == 0:
                penalty += np.cos(j * ratio * np.pi) * 0.4
            if j % 7 == 0 and i % 3 == 0:
                multiplier *= 1.03
        score += penalty * 0.9
        score *= adjustment
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item*2) + np.sqrt(cap) + np.sin(ratio * np.pi))
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 1.5) * (1 + ratio*1.2)
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**2) * (1 + 0.1 * np.tanh(cap - item))
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        elif cap % 2 == 0:
            priorities[i] *= 0.99
        else:
            priorities[i] *= 1.03
        if i % 4 == 0:
            priorities[i] *= 1.01 + 0.005 * i
        elif i % 4 == 3:
            priorities[i] *= 0.98 - 0.004 * i
        if priorities[i] == np.inf or np.isnan(priorities[i]):
            priorities[i] = np.inf
    return priorities
